import { getCollection } from 'astro:content'

import { entrySlug } from './docs-sidebar.ts'

// Build-time index of the autogenerated reference docs (config/models/api) and
// the hand-written guides that reference them. One source of truth drives all
// cross-linking: guide→reference auto-links, reference→guide backlinks, and
// guide→guide "related" links. Everything is derived from the docs content
// collection, so it stays correct as `pnpm gendocs` regenerates the reference
// pages.

const autogenDirs = new Set(['config', 'models', 'api'])

// type name (e.g. "BamAdapter") -> reference page url. A name can be documented
// as both a config and a state model; the config page is the more useful target
// for a guide mention (and it already links onward to its model), so prefer it.
export const typeNameToUrl = new Map<string, string>()

interface GuideRef {
  title: string
  url: string
}

// reference page id -> guides that link to it (the backlink direction)
const backlinks = new Map<string, GuideRef[]>()
// guide id -> set of reference ids it cites (for guide↔guide relatedness)
const guideRefs = new Map<string, Set<string>>()
// page id -> frontmatter title, for rendering related-guide link text
const titleById = new Map<string, string>()

function topDir(id: string): string {
  return id.split('/')[0]!
}

function urlFor(id: string): string {
  return `/docs/${entrySlug(id)}`
}

// Every /docs/... reference a guide makes, normalized to a known page id.
function referencedIds(body: string, known: Set<string>): Set<string> {
  const ids = new Set<string>()
  const re =
    /\]\(\s*(?:\.\.\/)*\/?(?:docs\/)?((?:config|models|api)\/[a-z0-9-]+)/gi
  let m: RegExpExecArray | null
  while ((m = re.exec(body)) !== null) {
    const id = m[1]!.toLowerCase()
    if (known.has(id)) {
      ids.add(id)
    }
  }
  return ids
}

let built: Promise<void> | undefined

// Populate the indexes once from the docs collection. Cached so repeated
// renderMarkdown calls share the work.
export function ensureAutogenIndex(): Promise<void> {
  built ??= (async () => {
    const docs = await getCollection('docs')
    const knownIds = new Set(docs.map(d => d.id))
    for (const d of docs) {
      titleById.set(d.id, d.data.title)
    }

    // config wins over models for a shared type name (loop models first so a
    // later config entry overwrites it)
    for (const dir of ['models', 'config']) {
      for (const d of docs) {
        if (topDir(d.id) === dir) {
          typeNameToUrl.set(d.data.title, urlFor(d.id))
        }
      }
    }

    for (const d of docs) {
      if (!autogenDirs.has(topDir(d.id))) {
        const refs = referencedIds(d.body ?? '', knownIds)
        guideRefs.set(d.id, refs)
        for (const targetId of refs) {
          const entry = { title: d.data.title, url: urlFor(d.id) }
          const list = backlinks.get(targetId)
          if (list) {
            list.push(entry)
          } else {
            backlinks.set(targetId, [entry])
          }
        }
      }
    }
  })()
  return built
}

export function backlinksFor(autogenId: string): GuideRef[] {
  return [...(backlinks.get(autogenId) ?? [])].sort((a, b) =>
    a.title.localeCompare(b.title),
  )
}

// Guides that share the most reference-page citations with this guide, capped
// and thresholded so the "Related guides" footer stays short rather than
// linking every guide that happens to mention a common adapter.
const RELATED_MIN_SHARED = 2
const RELATED_MAX = 4

export function relatedGuidesFor(guideId: string): GuideRef[] {
  const own = guideRefs.get(guideId)
  if (!own || own.size === 0) {
    return []
  }
  return [...guideRefs]
    .filter(([otherId]) => otherId !== guideId)
    .map(([otherId, refs]) => {
      let shared = 0
      for (const r of refs) {
        if (own.has(r)) {
          shared++
        }
      }
      return { id: otherId, shared }
    })
    .filter(x => x.shared >= RELATED_MIN_SHARED)
    .sort((a, b) => b.shared - a.shared || a.id.localeCompare(b.id))
    .slice(0, RELATED_MAX)
    .map(x => {
      const title = titleById.get(x.id) ?? x.id
      return { title, url: urlFor(x.id) }
    })
}
